mapper.select:
SELECT

FROM sys_log a
WHERE id = #{id}

SELECT
FROM sys_log a LEFT JOIN sys_user u ON u.id = a.user_id
AND a.type = #{query.type}
AND a.remote_addr = #{query.remoteAddr}
AND u.login_name LIKE CONCAT('%', #{query.userLoginName}, '%')
AND u.name LIKE CONCAT('%', #{query.userName}, '%')
AND a.title LIKE CONCAT('%', #{query.title}, '%')
AND a.request_uri LIKE CONCAT('%', #{query.requestUri}, '%')
AND a.log_date BETWEEN #{query.beginDate} AND #{query.endDate}
ORDER BY a.log_date DESC

